class JWTWrapper:
    def __init__(self, app: Flask = None):
        self.app = app
        self.jwt_manager = JWTManager()
        self.algorithms = {
            'HS256': self._verify_hs256,
            'RS256': self._verify_rs256
        }
        if app is not None:
            self.init_app(app)
    
    def init_app(self, app: Flask):
        self.app = app
        self.jwt_manager.init_app(app)
        app.extensions['jwt_wrapper'] = self
    
    def _verify_hs256(self, token: str, secret: str) -> Dict[str, Any]:
        try:
            payload = jwt.get_unverified_claims(token)
            # Verify with secret
            decoded = jwt.decode(token, secret, algorithms=['HS256'])
            return decoded
        except JWTError as e:
            raise ValueError(f"Invalid HS256 token: {str(e)}")
    
    def _verify_rs256(self, token: str, public_key: str) -> Dict[str, Any]:
        try:
            payload = jwt.get_unverified_claims(token)
            # Verify with public key
            decoded = jwt.decode(token, public_key, algorithms=['RS256'])
            return decoded
        except JWTError as e:
            raise ValueError(f"Invalid RS256 token: {str(e)}")
    
    def verify_token(self, token: str, algorithm: str, secret_or_key: str = None) -> Dict[str, Any]:
        if algorithm not in self.algorithms:
            raise ValueError(f"Unsupported algorithm: {algorithm}")
        
        if algorithm == 'HS256' and not secret_or_key:
            secret_or_key = self.app.config.get('JWT_SECRET_KEY')
        
        if algorithm == 'RS256' and not secret_or_key:
            secret_or_key = self.app.config.get('JWT_PUBLIC_KEY')
        
        return self.algorithms[algorithm](token, secret_or_key)
    
    def extract_payload(self, token: str, algorithm: str, secret_or_key: str = None) -> Dict[str, Any]:
        return self.verify_token(token, algorithm, secret_or_key)
    
    def get_current_user(self) -> Dict[str, Any]:
        try:
            token = request.headers.get('Authorization', '').replace('Bearer ', '')
            if not token:
                return None
            
            # Try to detect algorithm from token header
            header = jwt.get_unverified_claims(token)
            algorithm = header.get('alg', 'HS256')
            
            # Get appropriate key
            if algorithm == 'HS256':
                key = self.app.config.get('JWT_SECRET_KEY')
            else:
                key = self.app.config.get('JWT_PUBLIC_KEY')
            
            payload = self.verify_token(token, algorithm, key)
            return payload
        except Exception:
            return None

